// Função utilitária para criar um ZIP de múltiplos arquivos
// Requer JSZip (npm install jszip)
import JSZip from 'jszip';

export async function downloadZip(arquivos) {
  const zip = new JSZip();
  arquivos.forEach(({ nome, file }) => {
    if (file) zip.file(nome, file);
  });
  const blob = await zip.generateAsync({ type: 'blob' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'arquivos.zip';
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
